import{_ as e,c as p,o as r,ae as t}from"./chunks/framework.BvcDoAct.js";const s=JSON.parse('{"title":"RYUHEI (BE:FIRST)","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/08_RYUHEI.md","filePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/08_RYUHEI.md"}'),o={name:"zh-cn/Management2Extra/01_TalkAboutBMSG/08_RYUHEI.md"};function i(S,a,n,I,E,h){return r(),p("div",null,[...a[0]||(a[0]=[t('<p>Talk about BMSG - 08</p><h1 id="ryuhei-be-first" tabindex="-1">RYUHEI (BE:FIRST) <a class="header-anchor" href="#ryuhei-be-first" aria-label="Permalink to &quot;RYUHEI (BE:FIRST)&quot;">​</a></h1><h3 id="bmsg能够由自己切实去寻找意义-并创造出意义-这一点让我感到自豪" tabindex="-1">BMSG能够由自己切实去寻找意义，并创造出意义，这一点让我感到自豪 <a class="header-anchor" href="#bmsg能够由自己切实去寻找意义-并创造出意义-这一点让我感到自豪" aria-label="Permalink to &quot;BMSG能够由自己切实去寻找意义，并创造出意义，这一点让我感到自豪&quot;">​</a></h3><p><em>RYUHEI：2006年11月7日出生，爱知县出身</em><br><br><br> ————你觉得SKY-HI是怎样的人？之前你说过“是个聪明的人”。</p><p>还是一样，是个“聪明的人”。我觉得他一直都在观察一切、思考一切。随着BMSG作为事务所不断发展，社长对自己的一言一行都非常谨慎，在BE:FIRST的制作方面，也会先在脑海中构想好方向，然后很快地用语言表达出来并与我们共享，而且这种想法的实现度也非常高。我能感觉到，我们和成员之间的沟通也因此变得越来越顺畅了。我有时会去社长家里进行一对一的交流，在那种场合下，也经常会聊到“接下来想做这样的事情吧”之类关于未来的话题。我觉得“社长”这个角色，必须具备非常广阔的视野，而在这一点上，日高先生不仅作为艺人很出色，连作为社长所需要的那些艺人以外的能力也非常强。</p><h3 id="也会在社长家聚在一起进行创作工作" tabindex="-1">也会在社长家聚在一起进行创作工作 <a class="header-anchor" href="#也会在社长家聚在一起进行创作工作" aria-label="Permalink to &quot;也会在社长家聚在一起进行创作工作&quot;">​</a></h3><p>————这个一对一的交流通常是怎么安排的呢？</p><p>就是那种“最近没怎么聊，来聊聊吧”的轻松感觉。之前也有过几次，社长会和已经成年的成员一边喝酒一边聊，我则是喝水之类的。在那种场合下，也听过还没播出的《No No Girls》的内容，也会听新歌的demo，因为是非常私人的空间，所以什么话题都很容易聊。“Sailing”这首歌也是在社长家里，和SHUNTO、我，还有ソウチン（SOTA）四个人一起讨论歌词的方向。像这种创作相关的事情，也会去他家一起做。</p><p>————最近SKY-HI说过的话里，有什么让你印象特别深刻的吗？</p><p>他真的经常会说“作为BMSG想要去做这样的音乐”。感觉他是在塑造一个叫做BMSG的“人格”，并且完全把它内化，一直在思考相关的事情。说起来，前几天我和社长，还有ショウちゃん（Aile The Shota）一起在事务所看了《No No Girls》的播出，作为很喜欢文化这一块的人来说，有一位参赛者的歌声让我完全被击中了。不知不觉就和ショウちゃん两个人一起大叫起来了。那真的很开心。</p><p>————你在出道前，有一段时间是住在SKY-HI老家的吧。在日高家的生活是怎样的？</p><p>听说到现在为止，我还是在社长家待得最久的人（笑）。让我有种“原来一直住在别人家是这样的感觉啊”的体会。社长的父母对我真的就像对待孙子一样。早上他爸爸会说“RYUHEI，走吧！”然后开车送我到最近的车站，回来的时候也会来车站接我。偶尔还会带我去很不错的餐厅吃饭，真的很开心。</p><p>毕竟是“飞行员家庭”嘛。早上吃饭的时候会放《JET STREAM》（TOKYO FM）这个节目，以前在飞机上也能听到。一边听一边吃早餐。他爸爸还会说“听着这个吃早饭心情会很好”。就会有种“我现在是在天上吗？”的感觉（笑）。妈妈的英语也特别好，我就会想“真是个精英家庭啊”。也能理解为什么社长会去早稻田大学了。整个家庭都散发着一种高雅的氛围，让我觉得“这一家人太帅了！”（笑）。</p><h3 id="有新组合诞生时会觉得-大家一起把气氛带热起来吧" tabindex="-1">有新组合诞生时会觉得“大家一起把气氛带热起来吧” <a class="header-anchor" href="#有新组合诞生时会觉得-大家一起把气氛带热起来吧" aria-label="Permalink to &quot;有新组合诞生时会觉得“大家一起把气氛带热起来吧”&quot;">​</a></h3><p>————对于BMSG诞生了第二个组合MAZZEL，你有什么感受？</p><p>看到MAZZEL出道，并且在寻找“说到MAZZEL就是这个吧”“这个很有MAZZEL风格吧”的过程中，让我想起了BE:FIRST刚诞生时，我们也是这样去寻找属于自己的风格。2025年还会诞生第三个组合，但我们一直都是在做自己想做的事情，并且带着自信去呈现帅气的音乐。正因为如此，当有新的组合诞生时，我觉得大家可以用一种“我们一起把气氛带起来吧”的氛围去相互切磋、共同进步。</p><p>————在新组合诞生的时候，SKY-HI会不会说类似“要好好相处”或者“你们是竞争对手”之类的话？</p><p>不会。他只会说“这个成员这里很厉害”或者“这个成员如果做这种歌会很有意思吧”之类的话。</p><p>————对于“THE LAST PIECE”，你有什么想法？</p><p>我和RUI、TAIKI是在《THE FIRST》的选秀中认识的，到现在已经过了4年了。我们也一起参加过集训，年纪相近，还住过同一个房间，所以我真的非常支持他们，当然也很支持KANON。所以我也会想去现场看这个选秀。我觉得那三个人是最互相尊重、也是彼此最重要的存在，希望他们能加油。</p><p>————在“BMSG FES”上，你和他们一起表演了《14th Syndrome》，有感受到变化吗？</p><p>我觉得舞蹈方面确实有变化。能感觉到TAIKI一定非常认真地研究了自己的舞蹈方式，RUI在表现力上也有变化。再加上KANON，他们三个人的声音都完全不同，各自都有魅力，而且唱功也很高。作为同一代的人，我会觉得“果然真的很厉害啊！”</p><p>————最近他们三个人有对你说什么吗？</p><p>在“BMSG FES&#39;24”上表演的《Metamorphose》，他们对我说“很好！”这首歌也受到了其他Trainee的高度评价，经常被大家夸。那首歌确实很适合现场表演。</p><p>————真的很棒。听说你会和Trainee一起玩ONE PIECE卡牌游戏？</p><p>是的。我大概是BE:FIRST里和Trainee关系最好的一个吧。大家会一起吃披萨。我不是每天都能去上学，所以其实没有那么多和同龄人交流的机会，但听他们聊学校的事情时，会觉得“原来同龄人是这样聊天的啊，挺有意思的”。我和Trainee之间还挺合得来的。</p><p>————特别要好的有谁吗？</p><p>是谁呢？最有趣的是KAIRI。只要一和我对上眼，他就会一边说“うっす、うっす！”一边不停地鞠躬（笑）。真的特别搞笑。</p><p>————你在家里是最小的，在BE:FIRST里也是最年少的成员，当“哥哥”的位置是不是挺少见的？</p><p>确实是这样。KAIRI就算坐在我腿上，也会说“うっすうっす”，我就会觉得“KAIRI真可爱啊”。KAIRI也会玩ONE PIECE卡牌，所以在“BMSG FES”的等待时间我们也一起玩过，我把他打得很惨（笑）。真的可以说是压倒性胜利。</p><p>————最后再问一次，作为BMSG的艺人，你在什么样的时候会感到自豪？</p><p>我觉得这是一个很帅气的事务所。一直都在做有意义的事情。能够由我们自己去认真寻找意义，并且创造出意义，这样的公司让我感到很自豪。每一位艺人都有属于自己的“意义”，比如edhiii boi是在输出属于他自己的、有意义的音乐，Core和Shota也是如此。正因为大家都是以这样的方式在做音乐，所以我觉得作为一个事务所来说，它的整体质量很高，也具备很强的品牌力。“BMSG FES”也是一样，一直保持着“无论何时都要用我们自己的方式去表达”的这种状态。而对于能够接受这一点的BMSG粉丝们，我甚至会想说一句“你们支持的是一个很棒的事务所”。</p><blockquote><h3 id="from-sky-hi" tabindex="-1">from SKY-HI <a class="header-anchor" href="#from-sky-hi" aria-label="Permalink to &quot;from SKY-HI&quot;">​</a></h3><p>RYUHEI对音乐怀有非常纯粹的好奇心，而我们能够在不损害这种好奇心、反而是去培养它的前提下一起走到现在，这对BMSG来说是一次非常重要的成功经验。</p><p>他有时候也会有像小孩子一样的感性，让人替他捏一把汗（笑），但正是这种地方也很有魅力，让人忍不住想照顾他。</p><p>他是在一个会对人格形成产生巨大影响的时期，以艺人的身份度过的，所以我也感到有责任去引导他，让他的社会性在今后得到更好的提升。不过他本身也具备足够的人性与情感容量，是一个非常值得期待的人。正是因为迷上了他独有的那种气质，我们才一路走到了现在。</p></blockquote>',33)])])}const T=e(o,[["render",i]]);export{s as __pageData,T as default};
